select s.id, s.name, s.code, s.category_id, c.name as category_name, c.icon as category_icon, s.domain, s.site_type, s.site_function_type, s.setup_status, s.template_id, s.logo_url, s.favicon_url, s.description, s.seo_title, s.seo_keywords, s.seo_description, s.config, s.storage_config_id, s.default_locale, s.supported_locales, s.i18n_mode, s.is_personal, s.sort_order, s.status, s.del_flag, s.create_by, s.create_time, s.update_by, s.update_time, s.remark from gb_sites s left join gb_categories c on s.category_id = c.id and c.del_flag = '0'
s.del_flag = '0' and s.name like concat('%', #{name}, '%') and s.code = #{code} and s.category_id = #{categoryId} and s.domain like concat('%', #{domain}, '%') and s.site_type = #{siteType} and s.status = #{status}
order by s.sort_order asc, s.create_time desc

select s.id, s.name, s.code, s.category_id, c.name as category_name, c.icon as category_icon, s.domain, s.site_type, s.site_function_type, s.setup_status, s.template_id, s.logo_url, s.favicon_url, s.description, s.seo_title, s.seo_keywords, s.seo_description, s.config, s.storage_config_id, s.default_locale, s.supported_locales, s.i18n_mode, s.is_personal, s.sort_order, s.status, s.del_flag, s.create_by, s.create_time, s.update_by, s.update_time, s.remark, r.is_default from gb_sites s inner join gb_user_site_relation r on r.site_id = s.id and r.user_id = #{userId} left join gb_categories c on s.category_id = c.id and c.del_flag = '0'
s.del_flag = '0' and s.name like concat('%', #{site.name}, '%') and s.code = #{site.code} and s.category_id = #{site.categoryId} and s.domain like concat('%', #{site.domain}, '%') and s.site_type = #{site.siteType} and s.status = #{site.status}
order by r.is_default desc, s.sort_order asc, s.create_time desc

