update gb_sites
name = #{name}, code = #{code}, category_id = #{categoryId}, domain = #{domain}, site_type = #{siteType}, logo_url = #{logoUrl}, favicon_url = #{faviconUrl}, description = #{description}, seo_title = #{seoTitle}, seo_keywords = #{seoKeywords}, seo_description = #{seoDescription}, config = #{config}, storage_config_id = #{storageConfigId}, default_locale = #{defaultLocale}, supported_locales = #{supportedLocales}, i18n_mode = #{i18nMode}, is_personal = #{isPersonal}, site_function_type = #{siteFunctionType}, setup_status = #{setupStatus}, template_id = #{templateId}, sort_order = #{sortOrder}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where id = #{id}
